<template>


	<view class="wrap">

		<u-navbar :custom-back="backpage">
			<u-search v-model="keyword" placeholder="请输入订单号" height="56" @search="search" @custom="search">
			</u-search>

		</u-navbar>


		<scroll-view scroll-y style="height: 100%;width: 100%;background-color: #f5f7fa;" @scrolltolower="reachBottom">
			<view class="page-box">
				<view class="order" v-for="(order, orderindex) in list" :key="order.id">
					<view class="top">
						<view class="left" @click="paste(order.ordersn)">

							<view class="store">{{ order.ordersn }}</view>
							<u-icon name="zhuanfa" :size="30" color="rgb(94,94,94)"></u-icon>
							<!-- <u-icon name="arrow-right" color="rgb(203,203,203)" :size="26"></u-icon> -->
						</view>
						<view class="right" :style="{
									color:statusColor[order.status].color
								}">{{ order.status_text }}</view>
					</view>
					<view class="item" >
					
						<view class="content">
							<view class="content-box">
								<view class="label">
									商品名称
								</view>
								<view class="value">
									{{order.goods_name}}
								</view>
							</view>
							<view class="content-box">
								<view class="label">
									售后主题
								</view>
								<view class="value">
									{{order.subject}}
								</view>
							</view>
						
							<view class="content-box">
								<view class="label">
									创建时间
								</view>
								<view class="value">
									{{order.create_time}}
								</view>
							</view>
						</view>
						
					</view>

					<view class="bottom">
						<!-- <view class="more">
										<u-icon name="more-dot-fill" color="rgb(203,203,203)"></u-icon>
									</view> -->
						<!-- <view class="logistics btn">详情</view> -->

						<view class="evaluate btn" style="color: #000;border-color: #545454;border:2rpx solid #ccc;" @click="onGoods(order.goods_id,1,order )">再次购买</view>
						<view class="exchange btn" style="color: #000;border-color: #545454;border:2rpx solid #ccc;" @click="$util.on('/pages/buyer/addcomplain?ordersn='+order.ordersn)">查看详情
						</view>

					</view>
				</view>


				<u-loadmore :status="loadStatus" icon-type="circle" v-if="list.length >0 && loaded" />
			</view>
			<u-empty v-if="loaded &&  list.length == 0"></u-empty>


		</scroll-view>


	</view>



</template>

<script>
	export default {
		data() {
			return {

				keyword: '',
				sys: this.$util.sys(),
				limit: 10,


				loadStatus: 'loadmore',
				page: 1,

				count: 0,
				list: [],
				loaded: false,
				statusColor: [{
						color: '#999'
					},
					{
						color: '#f7b24b'
					},
					{
						color: '#ff8507'
					},
					{
						color: '#90dd90'
					},
					{
						color: '#ccc'
					},
					{
						color: '#f00'
					}
				],

				current: 0,
				swiperCurrent: 0,

				dx: 0,
			};
		},
		onLoad(e) {


			if (e.status) {
				this.swiperCurrent = e.status
				this.current = e.status

			}

			this.loadData(this.swiperCurrent);
		},
		methods: {
			backpage() {
				this.$util.back()
			},
			paste(val) {

				uni.setClipboardData({
					data: val,
					success: function() {
						uni.showToast({
							title: '复制成功',
							mask: false,
							duration: 1500,
							icon: 'none'
						});
					}
				})
			},
			reachBottom() {


				setTimeout(() => {
					this.loadData(this.current);
				}, 200);

			},
			search() {
				this.list = []
				this.page = 1
				this.loaded = false
				this.current = 0
				this.swiperCurrent = 0
				this.loadData(0);

			},
			// 页面数据
			async loadData(idx) {

uni.showLoading({
					mask: true,
					title: '加载中...',

				})
				await this.$u.api.complainList({

						keyword: this.keyword,
						page: this.page,
						limit: this.limit,
					})
					.then(res => {
						if (res.list.length == 0) {
							this.loadStatus = 'nomore'
						} else {
							if (this.list.length > 0) {
								this.list = this.list.concat(res.list)

							} else {
								this.list = res.list

							}

							if (res.list.length < this.limit) {
								this.loadStatus = 'nomore'
							} else {
								this.loadStatus = 'loadmore'
							}


							this.page++
						}
					}).catch(res => {})

				this.loaded = true;
				//loaded新字段用于表示数据加载完毕，如果为空可以显示空白页
uni.hideLoading()
				// console.log(item	);
			},
			// 总价
			totalPrice(item) {
				let price = 0;
				item.map(val => {
					price += parseFloat(val.price);
				});
				return price.toFixed(2);
			},
			// 总件数
			totalNum(item) {
				let num = 0;
				item.map(val => {
					num += val.number;
				});
				return num;
			},
			// tab栏切换
			change(index) {
				this.swiperCurrent = index;
				this.loadData(index);
			},
			transition({
				detail: {
					dx
				}
			}) {

				this.$refs.tabs.setDx(dx);
			},
			animationfinish({
				detail: {
					current
				}
			}) {

				this.$refs.tabs.setFinishCurrent(current);
				this.swiperCurrent = current;
				this.current = current;
				if (!this.orderList[current].loaded) {
					this.loadData(current)
				}
			}
		}
	};
</script>

<style scoped>
	/* #ifndef H5 */
	page {
		height: 100%;
		background-color: #f2f2f2;
	}

	/* #endif */
</style>

<style lang="scss" scoped scoped>
	.order {
		width: 710rpx;
		background-color: #ffffff;
		margin: 20rpx auto;
		border-radius: 20rpx;
		box-sizing: border-box;
		padding: 20rpx;
		font-size: 28rpx;

		.top {
			display: flex;
			justify-content: space-between;

			.left {
				display: flex;
				align-items: center;

				.store {
					margin: 0 10rpx;
					font-size: 24rpx;
					font-weight: bold;
				}
			}

			.right {
				color: $u-type-warning-dark;
			}
		}

		.item {
			display: flex;
			margin: 20rpx 0 0;
			justify-content: space-between;

			.left {
				margin-right: 20rpx;

				image {
					width: 160rpx;
					height: 160rpx;
					border-radius: 10rpx;
				}
			}

			.content {
				.title {
					font-size: 28rpx;
					line-height: 50rpx;
				}

				.type {
					margin: 10rpx 0;
					font-size: 24rpx;
					color: $u-tips-color;
				}

				.delivery-time {
					// color: #e5d001;
					font-size: 24rpx;
				}
				
				.content-box{
					display: flex;
					gap:20rpx;
				}
			}

			.right {
				margin-left: 10rpx;
				padding-top: 8rpx;
				text-align: right;

				.decimal {
					font-size: 24rpx;
					margin-top: 4rpx;
				}

				.number {
					color: $u-tips-color;
					font-size: 24rpx;
				}
			}
		}

		.total {
			// margin-top: 20rpx;
			text-align: right;
			font-size: 24rpx;

			.total-price {
				font-size: 32rpx;
			}

			.decimal {
				font-size: 24rpx;
				margin-top: 4rpx;
			}
		}

		.bottom {
			display: flex;
			margin-top: 20rpx;
			padding: 0 10rpx;
			gap: 20rpx;
			justify-content: flex-end;
			align-items: center;

			.btn {
				line-height: 52rpx;
				width: 160rpx;
				border-radius: 26rpx;
				border: 2rpx solid $u-border-color;
				font-size: 26rpx;
				text-align: center;
				color: $u-type-info-dark;
			}

			.evaluate {
				color: $u-type-warning-dark;
				border-color: $u-type-warning-dark;
			}
		}
	}

	.centre {
		text-align: center;
		margin: 200rpx auto;
		font-size: 32rpx;

		image {
			width: 164rpx;
			height: 164rpx;
			border-radius: 50%;
			margin-bottom: 20rpx;
		}

		.tips {
			font-size: 24rpx;
			color: #999999;
			margin-top: 20rpx;
		}

		.btn {
			margin: 80rpx auto;
			width: 200rpx;
			border-radius: 32rpx;
			line-height: 64rpx;
			color: #ffffff;
			font-size: 26rpx;
			background: linear-gradient(270deg, rgba(249, 116, 90, 1) 0%, rgba(255, 158, 1, 1) 100%);
		}
	}

	.wrap {
		display: flex;
		flex-direction: column;
		height: calc(100vh - var(--window-top));
		width: 100%;
	}

	.swiper-box {
		flex: 1;
		background-color: #f4f5f8;
	}

	.swiper-item {
		height: 100%;
	}
</style>
